    pre_value_vecs: &mut [ZeroCopyVecU64<[u8; 32]>],
    pre_roots: Vec<[u8; 32]>,
    pre_hash_chains: [ZeroCopyVecU64<[u8; 32]>; 2],
    merkle_tree_account: BatchedMerkleTreeAccount,
