    pub outputs: Vec<[u8; 32]>,
}

impl<const HEIGHT: usize> Default for MockBatchedForester<HEIGHT> {
    fn default() -> Self {
        let merkle_tree = MerkleTree::<Poseidon>::new(HEIGHT, 0);
        let input_queue_leaves = vec![];
        Self {
            merkle_tree,
            input_queue_leaves,
            output_queue_leaves: vec![],
            active_leaves: vec![],
            tx_events: vec![],
        }
