231→// Check that new addresses are assigned correctly to the compressed output accounts specified by index
232→#[profile]
233→pub fn check_new_address_assignment<'a, 'info, T: InstructionData<'a>>(
234→    inputs: &WrappedInstructionData<'a, T>,
235→    cpi_ix_data: &InsertIntoQueuesInstructionDataMut<'_>,
236→) -> std::result::Result<(), SystemProgramError> {
237→    for (derived_addresses, new_addresses) in
238→        cpi_ix_data.addresses.iter().zip(inputs.new_addresses())
239→    {
240→        if let Some(assigned_account_index) = new_addresses.assigned_compressed_account_index() {
241→            let output_account = inputs
242→                .get_output_account(assigned_account_index)
243→                .ok_or(SystemProgramError::NewAddressAssignedIndexOutOfBounds)?;
244→
245→            if derived_addresses.address
246→                != output_account
247→                    .address()
248→                    .ok_or(SystemProgramError::AddressIsNone)?
249→            {
250→                msg!(format!(
251→                    "derived_addresses.address {:?} != account address {:?}",
252→                    derived_addresses.address,
253→                    output_account.address()
254→                )
255→                .as_str());
256→                msg!(format!(
257→                    "account owner {:?}",
258→                    solana_pubkey::Pubkey::new_from_array(output_account.owner().into())
259→                )
260→                .as_str());
261→                msg!(format!(
262→                    "account merkle_tree_index {:?}",
263→                    output_account.merkle_tree_index()
264→                )
265→                .as_str());
266→                return Err(SystemProgramError::AddressDoesNotMatch);
267→            }
268→        }
269→    }
270→    Ok(())
271→}
