 58→/// A mock function which imitates a Merkle tree program instruction for
 59→/// inserting nullifiers from the queue to the tree.
 60→#[allow(clippy::too_many_arguments)]
 61→fn program_update<H>(
 62→    // PDAs
 63→    queue: &mut RefMut<'_, HashSet>,
 64→    merkle_tree: &mut RefMut<'_, IndexedMerkleTree<H, usize, MERKLE_TREE_HEIGHT, NET_HEIGHT>>,
 65→    // Instruction data
 66→    changelog_index: u16,
 67→    indexed_changelog_index: u16,
 68→    queue_index: u16,
 69→    low_nullifier: IndexedElement<usize>,
 70→    low_nullifier_next_value: &BigUint,
 71→    low_nullifier_proof: &mut BoundedVec<[u8; 32]>,
 72→) -> Result<IndexedMerkleTreeUpdate<usize>, IndexedMerkleTreeError>
 73→where
 74→    H: Hasher,
 75→{
 76→    // Get the nullifier from the queue.
 77→    let nullifier = queue
 78→        .get_unmarked_bucket(queue_index as usize)
 79→        .unwrap()
 80→        .unwrap();
 81→
 82→    // Update the Merkle tree.
 83→    let update = merkle_tree.update(
 84→        usize::from(changelog_index),
 85→        usize::from(indexed_changelog_index),
 86→        nullifier.value_biguint(),
 87→        low_nullifier.clone(),
 88→        low_nullifier_next_value.clone(),
 89→        low_nullifier_proof,
 90→    )?;
 91→
 92→    // Mark the nullifier.
 93→    queue
 94→        .mark_with_sequence_number(queue_index as usize, merkle_tree.sequence_number())
 95→        .unwrap();
 96→
 97→    Ok(update)
 98→}
